// Recibir config del portal
const body = $('1. Webhook Exportar').first().json.body || {};
const facturas = $('2. Leer Facturas NocoDB').first().json.list || [];

// Columnas disponibles con sus labels para el CSV
const TODAS_COLUMNAS = {
  'numero_factura': 'Num. Factura',
  'fecha_factura': 'Fecha Factura',
  'tipo_documento': 'Tipo',
  'nif_emisor': 'NIF Emisor',
  'nombre_emisor': 'Nombre Emisor',
  'base_imponible': 'Base Imponible',
  'total_factura': 'Total Factura',
  'base_iva_21': 'Base IVA 21%',
  'cuota_iva_21': 'Cuota IVA 21%',
  'base_iva_10': 'Base IVA 10%',
  'cuota_iva_10': 'Cuota IVA 10%',
  'base_iva_4': 'Base IVA 4%',
  'cuota_iva_4': 'Cuota IVA 4%',
  'base_iva_0': 'Base IVA 0%',
  'cuota_iva_0': 'Cuota IVA 0%',
  'tipo_iva': 'Tipo IVA Principal',
  'cuota_iva': 'Cuota IVA Total',
  'tipo_retencion': '% Retención',
  'cuota_retencion': 'Cuota Retención',
  'cuenta_gasto': 'Cuenta Gasto',
  'cuenta_tercero': 'Cuenta Tercero',
  'estado': 'Estado',
  'confianza_ia': 'Confianza IA',
  'fecha_contabilizacion': 'Fecha Contabilización',
  'numero_asiento': 'Nº Asiento',
  'empresa_id': 'Empresa ID',
  'archivo_url': 'URL Archivo'
};

// Columnas solicitadas (por defecto las más comunes)
const columnasDefault = [
  'numero_factura','fecha_factura','tipo_documento','nif_emisor','nombre_emisor',
  'base_imponible','base_iva_21','cuota_iva_21','base_iva_10','cuota_iva_10',
  'base_iva_4','cuota_iva_4','base_iva_0','cuota_iva_0',
  'tipo_retencion','cuota_retencion','total_factura','cuenta_gasto','cuenta_tercero'
];

const columnas = body.columnas || columnasDefault;
const separador = body.separador || ';';
const incluirCabecera = body.incluir_cabecera !== false;

// Generar CSV
const lineas = [];

// Cabecera
if (incluirCabecera) {
  const cabecera = columnas.map(c => TODAS_COLUMNAS[c] || c);
  lineas.push(cabecera.join(separador));
}

// Datos
for (const f of facturas) {
  const fila = columnas.map(col => {
    let val = f[col];
    if (val === null || val === undefined) val = '';
    // Escapar comillas y separadores en strings
    val = String(val);
    if (val.includes(separador) || val.includes('"') || val.includes('\n')) {
      val = '"' + val.replace(/"/g, '""') + '"';
    }
    return val;
  });
  lineas.push(fila.join(separador));
}

const csv = lineas.join('\n');

// Formato de respuesta según lo pedido
const formato = body.formato || 'download';

if (formato === 'base64') {
  return [{
    json: {
      success: true,
      total_facturas: facturas.length,
      columnas_incluidas: columnas,
      csv_base64: Buffer.from(csv, 'utf-8').toString('base64'),
      filename: 'facturas_' + new Date().toISOString().split('T')[0] + '.csv'
    }
  }];
} else {
  // download - devolver CSV directamente
  return [{
    json: {
      success: true,
      total_facturas: facturas.length,
      columnas_incluidas: columnas,
      csv_content: csv,
      filename: 'facturas_' + new Date().toISOString().split('T')[0] + '.csv'
    }
  }];
}

